// entries/landing/LandingPage.schema.tsx
import {Config, Field} from 'alinea'

export const LandingPage = Config.document('Landing page', {
  fields: {
    title: Field.text('Title', {required: true}),
    path: Field.path('Path', {readOnly: true, initialValue: ''})
  }
})

// entries/landing/LandingPage.tsx
import {Infer} from 'alinea'
import {LandingPage} from './LandingPage.schema'

type LandingData = Infer<typeof LandingPage>

export function LandingPageView({page}: {page: LandingData}) {
  return <h1>{page.title}</h1>
}

// cms.tsx
import {Config} from 'alinea'
import {createCMS} from 'alinea/next'
import {LandingPage} from '@/entries/landing/LandingPage.schema'

export const cms = createCMS({
  schema: {LandingPage},
  workspaces: {
    main: Config.workspace('Main', {
      source: 'content',
      mediaDir: 'public',
      roots: {
        pages: Config.root('Pages', {
          contains: ['LandingPage'],
          children: {
            index: Config.page({
              type: LandingPage,
              fields: {
                title: 'Welcome',
                path: ''
              }
            })
          }
        }),
        media: Config.media()
      }
    })
  },
  handlerUrl: '/api/cms',
  dashboardFile: 'admin.html',
  preview: true
})

// app/page.tsx
import {cms} from '@/cms'
import {LandingPageView} from '@/entries/landing/LandingPage'

export default async function Page() {
  const page = await cms.get({url: '/'})
  return <LandingPageView page={page} />
}
